import React from 'react';
import {
  Box,
  Breadcrumbs,
  Button,
  Checkbox,
  Grid,
  Slider,
  TextareaAutosize,
  TextField,
  Typography,
} from '@material-ui/core';
import { Layout } from './Layout';
import styled from 'styled-components';
import ArrowBackIosRoundedIcon from '@material-ui/icons/ArrowBackIosRounded';

const marks = [
  {
    value: 0,
    label: '0',
  },
  {
    value: 10,
    label: '10',
  },
